const body = $json.body ?? $json;
const items = Array.isArray(body.items) ? body.items : [];
const reorderItems = items.map((item) => {
  const onHand = Number(item.onHand ?? 0);
  const par = Number(item.par ?? item.targetStock ?? 0);
  const minimum = Number(item.minimum ?? Math.ceil(par * 0.35));
  const caseSize = Number(item.caseSize ?? 1);
  const neededUnits = Math.max(par - onHand, 0);
  const cases = caseSize > 0 ? Math.ceil(neededUnits / caseSize) : neededUnits;
  return {
    sku: item.sku ?? item.name,
    name: item.name ?? item.sku,
    onHand,
    minimum,
    par,
    caseSize,
    vendor: item.vendor ?? 'unassigned',
    reorder: onHand <= minimum,
    suggestedUnits: neededUnits,
    suggestedCases: cases
  };
}).filter((item) => item.reorder);
return [{
  json: {
    workflow: 'qsr-inventory-reorder-watch',
    storeId: body.storeId ?? 'unknown',
    checkedAt: new Date().toISOString(),
    reorderCount: reorderItems.length,
    reorderItems,
    nextStep: reorderItems.length ? 'send_supplier_or_manager_approval' : 'no_reorder_needed'
  }
}];
